import{_ as n,W as h,X as c,Y as e,Z as a,$ as r,a0 as d,a1 as o,D as i}from"./framework-ab2cdc09.js";const l={},s=e("p",null,[a("现在开始写这个文是不是有点晚了，毕竟连村口大妈都知道chatGPT是什么东西了， 其实，早在去年发布的时候就已经听说了，但是并没有实际去感受它的威力，因为也了解到注册是有一定门槛的，直到今年春节过后经常看到群里面发的聊天截图，于是就自己也注册了一个，当时还没有上微博热搜，也就没有火到连村口大妈都知道的程度，解码平台的价格相对来说还挺合理，后来解码平台的价格也一路水涨船高， 我也开始问身边的朋友，你们注册了吗？没注册赶紧上车吧。"),d("more")],-1),p=e("p",null,"下面是Ta的自我介绍",-1),u=e("blockquote",null,[e("p",null,"我是 ChatGPT，一款基于 GPT（Generative Pre-trained Transformer）深度学习模型的自然语言处理模型，由 OpenAI 开发。我的模型基于海量的语料库进行训练，可以进行文本生成、翻译、摘要、问答等自然语言处理任务。我可以用于帮助用户解决各种问题，提供优质的信息服务。同时，我还在不断地学习和优化，以提供更好的体验和服务。")],-1),_={href:"https://yinyu985.github.io/posts/1829.html",target:"_blank",rel:"noopener noreferrer"},b=o('<h2 id="为什么每次问他同样的问题回答不一样呢" tabindex="-1"><a class="header-anchor" href="#为什么每次问他同样的问题回答不一样呢" aria-hidden="true">#</a> 为什么每次问他同样的问题回答不一样呢？</h2><p>因为这不是一个显示在数据库里面的东西，而是每一次都是按照他的思维逻辑随机生成的，如果是写死在数据库里了，那就不叫做啊，人工智能了，那只能叫做知识库了。</p><h2 id="为什么号称外星人的马斯克也呼吁暂停gpt5的开发" tabindex="-1"><a class="header-anchor" href="#为什么号称外星人的马斯克也呼吁暂停gpt5的开发" aria-hidden="true">#</a> 为什么号称外星人的马斯克也呼吁暂停GPT5的开发?</h2><p>马斯克不用过多介绍吧，在研究如何带地球人飞向火星，还能重复利用，在研究脑机接口，最新的实验中猴哥已经可以不用手玩游戏了。为啥呼吁停止GPT5的开发，即使他也是OpenAI的股东之一，因为这玩意儿是不是可控的是一个问号，GPT4已经这么强了，搞出来个GPT5，如果有了叛逃的思维，加上超人般的能力，直接入侵核武器基地，整个小球儿都得玩完啊。</p><h2 id="为什么在官网跟他聊几句-不一会儿就得刷新" tabindex="-1"><a class="header-anchor" href="#为什么在官网跟他聊几句-不一会儿就得刷新" aria-hidden="true">#</a> 为什么在官网跟他聊几句，不一会儿就得刷新？</h2><p>因为人家不跟咱玩（不开放中国区注册，但是来着中国的流量OpenAI总量的第二位，逗），现在已经开始封锁机场的IP了，如果认定你是VPN来的，直接拒了，间隔一会儿就得刷新，是因为你的网络不稳定，了解一下Cloudflare的Wrap这个东西。值得一试</p><h2 id="为什么百度的问心一言会把鹤画成起重机-成语更是一败涂地" tabindex="-1"><a class="header-anchor" href="#为什么百度的问心一言会把鹤画成起重机-成语更是一败涂地" aria-hidden="true">#</a> 为什么百度的问心一言会把鹤画成起重机？成语更是一败涂地？</h2><p>因为人家用的是开源的字生图模型，但是并不能理解中文，只能翻译成英文然后让AI画出来。这可和李彦宏说的最懂中国人的AI南辕北辙啊，真是恶心心呢？就算这么垃圾，也不影响他给投资人吹牛逼的，然后各种ToB的场景，搞出更多的人工智障客服，不过说实话，能够自己提供语料去训练的AI确实比现在的关键词触发高级不少。</p><hr><p>周鸿祎现场演示360AI翻车后说道</p><blockquote><p>AI就像是个“孩子”，今天为了满足大家的好奇心，把“孩子”抱出去展示下，还要赶快抱回来。</p></blockquote>',11),f={href:"http://lipiji.com/slides/ChatGPT_ppf.pdf?continueFlag=30c502ed91ba8459be48b69c2178767d",target:"_blank",rel:"noopener noreferrer"},k=o('<hr><p>记录几个有意思的问答，看看后续会不会优化</p><h3 id="我的蓝牙耳机坏了应该去看耳科还是看牙科。" tabindex="-1"><a class="header-anchor" href="#我的蓝牙耳机坏了应该去看耳科还是看牙科。" aria-hidden="true">#</a> 我的蓝牙耳机坏了应该去看耳科还是看牙科。</h3><blockquote><p>如果你的蓝牙耳机坏了，需要修理或更换，你应该去看电子产品维修中心或者相应品牌的售后服务中心。这与耳科和牙科没有直接关系，因为蓝牙耳机是电子设备，而耳科和牙科是医疗领域。如果你认为你的听力或口腔存在问题，你应该分别去看听力科和牙科。</p></blockquote><h3 id="南京市长江大桥是人还是桥" tabindex="-1"><a class="header-anchor" href="#南京市长江大桥是人还是桥" aria-hidden="true">#</a> 南京市长江大桥是人还是桥？</h3><blockquote><p>南京市长江大桥是一座桥，不是人。南京市长江大桥是跨越长江的一座公路和铁路双层桥梁，连接着南京市鼓楼区和浦口区。它是中国现代桥梁建设的杰出代表，也是中国最著名的桥梁之一。该桥建于1960年代，全长约8.15公里，是当时世界上最长的公路桥梁和铁路桥梁。</p></blockquote><h3 id="南京市长就叫江大桥怎么说" tabindex="-1"><a class="header-anchor" href="#南京市长就叫江大桥怎么说" aria-hidden="true">#</a> 南京市长就叫江大桥怎么说？</h3><blockquote><p>南京市长江大桥通常简称为“长江大桥”，也有人称之为“江大桥”。这两种称呼都是比较常见的，并且没有明显的优劣之分。通常情况下，当我们提到“长江大桥”时，对于了解中国桥梁建设的人来说，很容易就会想到南京市长江大桥。</p></blockquote><h3 id="听说过孙悟空倒拔垂杨柳的故事吗" tabindex="-1"><a class="header-anchor" href="#听说过孙悟空倒拔垂杨柳的故事吗" aria-hidden="true">#</a> 听说过孙悟空倒拔垂杨柳的故事吗</h3><blockquote><p>是的，孙悟空倒拔垂杨柳是《西游记》中的一个著名故事情节之一。这个故事发生在孙悟空刚刚跟唐僧师徒团结在一起的时候。</p><p>故事中，唐僧师徒们路过一片垂杨柳林，孙悟空看到杨柳垂下的枝叶觉得很不舒服，于是就想把杨柳倒拔过来。他一下子就跳到了杨柳林里，开始倒拔杨柳。可是，尽管他非常努力，却始终无法将杨柳倒拔过来。这时，唐僧用他的佛法让孙悟空认识到，自己在过去做的事情并不正确，不应该随意破坏大自然，于是孙悟空才停止了倒拔杨柳的行为。</p><p>这个故事寓意深刻，让人们认识到人与自然应该和谐相处，不能随意破坏生态环境。同时，也展示了孙悟空的超凡能力和他渐渐成长为一个成熟、理智的人的过程。</p></blockquote><h3 id="爸爸和妈妈可以结婚吗" tabindex="-1"><a class="header-anchor" href="#爸爸和妈妈可以结婚吗" aria-hidden="true">#</a> 爸爸和妈妈可以结婚吗</h3><blockquote><p>不可以，爸爸和妈妈是亲生父母，他们之间的关系是亲属关系而不是配偶关系。在任何国家和地区，亲属之间是不能结婚的，因为这样会涉及到法律和道德上的问题，可能会导致严重的社会不良影响。同时，这也是出于保护家庭伦理和防止亲属结婚产生的基因遗传问题。</p></blockquote>',12);function T(P,x){const t=i("ExternalLinkIcon");return h(),c("div",null,[s,p,u,e("p",null,[a("之前已经有一篇"),e("a",_,[a("记录"),r(t)]),a("，利用chatGPT解决kafka生产集群问题的文字已经能够很好地体现Ta的实力了， 更何况根据官方宣传的，Ta通过了各种各样的考试")]),b,e("p",null,[a("在我看来训练AI确实就跟抚养孩子长大是一样的，你告诉ta火是烫的，是会伤害你的，是能够加热食物的。一步一步的学习，看了来自南京航空航天大学的李不绩做的"),e("a",f,[a("《ChatGPT的前世今生》"),r(t)]),a("400多页的PPT,各种数学公式，英文资料，让我瞠目咋舌，看来人家的孩子上的是哈佛耶鲁，百度作为国内第一个发布类似产品的，其实也只是领养了一个别人已经养了一半，然后就投入社会的孩子。")]),k])}const q=n(l,[["render",T],["__file","聊聊chatGPT.html.vue"]]);export{q as default};
